import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { loadService } from "../services";
import "../styles/CreateLoad.css";

const CITIES = [
  "Select Pickup City",
  "Aruppukottai",
  "Kariapatti",
  "Tirunelveli",
  "Nagercoil",
  "Kanyakumari",
  "Madurai",
  "Theni",
  "Dindigul",
  "Coimbatore",
  "Salem",
  "Erode",
  "Chennai",
  "Bangalore",
  "Hyderabad",
  "Mumbai",
  "Delhi",
  "Pune",
  "Kolkata",
  "Jaipur",
];

const CreateLoad = () => {
  const [formData, setFormData] = useState({
    title: "",
    description: "",
    pickupLocation: "",
    dropLocation: "",
    weight: "",
    price: "",
  });
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleLocationSelect = async (type, latitude, longitude) => {
    try {
      // Reverse geocode to get city name from coordinates
      const response = await fetch(
        `https://nominatim.openstreetmap.org/reverse?format=json&lat=${latitude}&lon=${longitude}`,
      );
      const data = await response.json();

      // Extract city name from the address
      const address = data.address || {};
      const city =
        address.city ||
        address.town ||
        address.village ||
        address.county ||
        data.name ||
        "Unknown";

      setFormData((prev) => ({
        ...prev,
        [type === "pickup" ? "pickupLocation" : "dropLocation"]: city,
      }));

      // Close map after selection
      if (type === "pickup") {
        setShowPickupMap(false);
      } else {
        setShowDropMap(false);
      }
    } catch (err) {
      console.error("Error retrieving location:", err);
      setError("Failed to get location name from map");
    }
  };

  const validateForm = () => {
    if (
      !formData.title ||
      !formData.pickupLocation ||
      !formData.dropLocation ||
      !formData.weight ||
      !formData.price
    ) {
      setError("All required fields must be filled");
      return false;
    }
    if (formData.weight <= 0 || formData.price <= 0) {
      setError("Weight and price must be greater than 0");
      return false;
    }
    return true;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");

    if (!validateForm()) return;

    setLoading(true);
    try {
      await loadService.createLoad(formData);
      navigate("/loads");
    } catch (err) {
      setError(err.response?.data?.message || "Failed to create load");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="create-load-container">
      <div className="create-load-box">
        <h2>Create New Load</h2>
        {error && <div className="error-message">{error}</div>}
        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Title *</label>
            <input
              type="text"
              name="title"
              value={formData.title}
              onChange={handleChange}
              placeholder="Load title"
            />
          </div>
          <div className="form-group">
            <label>Description</label>
            <textarea
              name="description"
              value={formData.description}
              onChange={handleChange}
              placeholder="Load description"
              rows="4"
            />
          </div>
          <div className="form-row">
            <div className="form-group">
              <label>Pickup Location *</label>
              <div className="location-input-group">
                <input
                  type="text"
                  name="pickupLocation"
                  value={formData.pickupLocation}
                  onChange={handleChange}
                  placeholder="Pickup location or click map"
                />
                <button
                  type="button"
                  className="btn-map"
                  onClick={() => setShowPickupMap(true)}
                  title="Select from map"
                >
                  📍 Map
                </button>
              </div>
            </div>
            <div className="form-group">
              <label>Drop Location *</label>
              <div className="location-input-group">
                <input
                  type="text"
                  name="dropLocation"
                  value={formData.dropLocation}
                  onChange={handleChange}
                  placeholder="Drop location or click map"
                />
                <button
                  type="button"
                  className="btn-map"
                  onClick={() => setShowDropMap(true)}
                  title="Select from map"
                >
                  📍 Map
                </button>
              </div>
            </div>
          </div>
          <div className="form-row">
            <div className="form-group">
              <label>Weight (kg) *</label>
              <input
                type="number"
                name="weight"
                value={formData.weight}
                onChange={handleChange}
                placeholder="Weight"
                step="0.1"
              />
            </div>
            <div className="form-group">
              <label>Price ($) *</label>
              <input
                type="number"
                name="price"
                value={formData.price}
                onChange={handleChange}
                placeholder="Price"
                step="0.01"
              />
            </div>
          </div>
          <button type="submit" disabled={loading} className="btn-primary">
            {loading ? "Creating..." : "Create Load"}
          </button>
        </form>

        {/* Pickup Location Map Modal */}
        {showPickupMap && (
          <LocationMapModal
            title="Select Pickup Location"
            onSelect={(lat, lon) => handleLocationSelect("pickup", lat, lon)}
            onClose={() => setShowPickupMap(false)}
          />
        )}

        {/* Drop Location Map Modal */}
        {showDropMap && (
          <LocationMapModal
            title="Select Drop Location"
            onSelect={(lat, lon) => handleLocationSelect("drop", lat, lon)}
            onClose={() => setShowDropMap(false)}
          />
        )}
      </div>
    </div>
  );
};

// Map Modal Component
const LocationMapModal = ({ title, onSelect, onClose }) => {
  const [mapElement, setMapElement] = useState(null);
  const mapContainer = React.useRef(null);

  React.useEffect(() => {
    if (!mapContainer.current) return;

    // Load Leaflet library and CSS
    if (!window.L) {
      const link = document.createElement("link");
      link.rel = "stylesheet";
      link.href =
        "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.min.css";
      document.head.appendChild(link);

      const script = document.createElement("script");
      script.src =
        "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.min.js";
      script.onload = initMap;
      document.body.appendChild(script);
    } else {
      initMap();
    }

    function initMap() {
      const L = window.L;

      // Create map centered on India
      const map = L.map(mapContainer.current).setView([20.5937, 78.9629], 5);

      L.tileLayer("https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png", {
        attribution: "&copy; OpenStreetMap contributors",
        maxZoom: 19,
      }).addTo(map);

      // Handle map clicks
      map.on("click", (e) => {
        const { lat, lng } = e.latlng;
        onSelect(lat, lng);
      });

      setMapElement(map);
    }

    return () => {
      // Cleanup if needed
    };
  }, [onSelect]);

  return (
    <div className="map-modal-overlay" onClick={onClose}>
      <div className="map-modal-content" onClick={(e) => e.stopPropagation()}>
        <div className="map-modal-header">
          <h3>{title}</h3>
          <button className="map-modal-close" onClick={onClose}>
            ✕
          </button>
        </div>
        <p className="map-modal-instruction">
          Click on the map to select a location
        </p>
        <div ref={mapContainer} className="map-container"></div>
      </div>
    </div>
  );
};

export default CreateLoad;
